// Form: prevent page reload on submit
function LoginForm({ onLogin }) {
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');

  function handleSubmit(event) {
    event.preventDefault(); // ← without this, the browser navigates away
    onLogin({ email, password });
  }

  return (
    <form onSubmit={handleSubmit}>
      <input value={email}    onChange={e => setEmail(e.target.value)} type="email" />
      <input value={password} onChange={e => setPassword(e.target.value)} type="password" />
      <button type="submit">Login</button>
    </form>
  );
}

// Card with an expandable area — click the card to expand,
// click Delete to delete without expanding
function Card({ item, onDelete }) {
  const [expanded, setExpanded] = useState(false);

  function handleCardClick() {
    setExpanded(prev => !prev);
  }

  function handleDeleteClick(event) {
    event.stopPropagation(); // ← without this, handleCardClick also fires
    onDelete(item.id);
  }

  return (
    <div onClick={handleCardClick}>
      <h3>{item.title}</h3>
      {expanded && <p>{item.body}</p>}
      <button onClick={handleDeleteClick}>Delete</button>
    </div>
  );
}

function NavItem({ href, label, onActivate }) {
  function handleClick(event) {
    event.preventDefault();       // don't navigate to href
    event.stopPropagation();      // don't bubble to the nav's onClick
    onActivate(href);
  }

  return <a href={href} onClick={handleClick}>{label}</a>;
}

