// If React's handler calls stopPropagation(), both native listeners still fire
// If React's handler calls stopImmediatePropagation(), neither fires

// In practice: if you only use React event props, you rarely need stopImmediatePropagation

function FileList({ files }) {
  const [selected, setSelected] = useState(null);

  // Parent delegates — handles row clicks
  function handleRowClick(event) {
    const id = Number(event.currentTarget.dataset.id);
    setSelected(id);
  }

  function handleRenameClick(event, id) {
    event.stopPropagation(); // don't also select the row
    startRenaming(id);
  }

  function handleDeleteClick(event, id) {
    event.stopPropagation(); // don't also select the row
    if (confirm('Delete?')) deleteFile(id);
  }

  return (
    <ul>
      {files.map(file => (
        <li
          key={file.id}
          data-id={file.id}
          onClick={handleRowClick}
          style={{ background: selected === file.id ? '#dbeafe' : undefined }}
        >
          {file.name}
          <button onClick={e => handleRenameClick(e, file.id)}>Rename</button>
          <button onClick={e => handleDeleteClick(e, file.id)}>Delete</button>
        </li>
      ))}
    </ul>
  );
}

function Dropdown({ options, value, onChange }) {
  const [open, setOpen] = useState(false);

  useEffect(() => {
    if (!open) return;
    function handleDocumentClick() { setOpen(false); }
    document.addEventListener('click', handleDocumentClick);
    return () => document.removeEventListener('click', handleDocumentClick);
  }, [open]);

  function handleDropdownClick(event) {
    event.stopPropagation(); // don't bubble to the document listener
    setOpen(prev => !prev);
  }

  return (
    <div onClick={handleDropdownClick}>
      <button>{value || 'Select...'}</button>
      {open && (
        <ul>
          {options.map(opt => (
            <li key={opt} onClick={() => { onChange(opt); setOpen(false); }}>
              {opt}
            </li>
          ))}
        </ul>
      )}
    </div>
  );
}

// div clicks have no browser default to prevent — calling it does nothing here
<div onClick={e => { e.preventDefault(); toggle(); }}>Content</div>

// Only needed on elements with defaults: <a>, <form>, <input type="checkbox">, etc.

// React 17+: events attach to the root container, not document
// stopPropagation in a React handler DOES prevent native listeners on document

// React 16: events attach to document
// stopPropagation in a React handler does NOT prevent native listeners on document
// (because both are on the same element — document — by the time they fire)

// Safe cross-version approach: use a ref to detect click-outside by DOM containment
const ref = useRef(null);
useEffect(() => {
  function handleClick(event) {
    if (ref.current && !ref.current.contains(event.target)) {
      setOpen(false);
    }
  }
  document.addEventListener('click', handleClick);
  return () => document.removeEventListener('click', handleClick);
}, []);

function Editor({ content, onSave }) {
  function handleKeyDown(event) {
    // Ctrl+S / Cmd+S — save
    if ((event.ctrlKey || event.metaKey) && event.key === 's') {
      event.preventDefault(); // stop browser's "Save Page" dialog
      onSave(content);
    }
    // Ctrl+Z / Cmd+Z — undo (custom)
    if ((event.ctrlKey || event.metaKey) && event.key === 'z') {
      event.preventDefault(); // stop browser's default undo
      undo();
    }
    // Escape — cancel edit
    if (event.key === 'Escape') {
      // Escape has no browser default, but stopPropagation prevents
      // a parent modal from catching Escape and closing
      event.stopPropagation();
      cancelEdit();
    }
  }

  return (
    <textarea
      value={content}
      onKeyDown={handleKeyDown}
      onChange={e => setContent(e.target.value)}
    />
  );
}

function ImageViewer({ src }) {
  const [menu, setMenu] = useState(null); // { x, y } or null

  function handleContextMenu(event) {
    event.preventDefault(); // suppress the browser context menu
    setMenu({ x: event.clientX, y: event.clientY });
  }

  function handleCloseMenu() { setMenu(null); }

  return (
    <div onContextMenu={handleContextMenu} onClick={handleCloseMenu}>
      <img src={src} alt="" />
      {menu && (
        <ul
          style={{ position: 'fixed', top: menu.y, left: menu.x }}
          onClick={e => e.stopPropagation()} // don't close when clicking menu items
        >
          <li onClick={() => { download(src); handleCloseMenu(); }}>Download</li>
          <li onClick={() => { copyLink(src); handleCloseMenu(); }}>Copy link</li>
        </ul>
      )}
    </div>
  );
}

import { render, screen, fireEvent } from '@testing-library/react';
import LoginForm from './LoginForm';

test('form submit prevents page navigation', () => {
  const onLogin = jest.fn();
  render(<LoginForm onLogin={onLogin} />);

  const form = screen.getByRole('form');
  // Create a submit event with a spy on preventDefault
  const submitEvent = new Event('submit', { bubbles: true, cancelable: true });
  const preventDefaultSpy = jest.spyOn(submitEvent, 'preventDefault');

  fireEvent(form, submitEvent);

  expect(preventDefaultSpy).toHaveBeenCalled();
  expect(onLogin).toHaveBeenCalled();
});

test('delete button does not bubble to row', () => {
  const onDelete = jest.fn();
  const onRowClick = jest.fn();
  render(<FileRow file={{ id: 1, name: 'report.pdf' }} onDelete={onDelete} onRowClick={onRowClick} />);

  fireEvent.click(screen.getByRole('button', { name: 'Delete' }));

  expect(onDelete).toHaveBeenCalledWith(1);
  expect(onRowClick).not.toHaveBeenCalled(); // stopped by stopPropagation
});

// What React Router's <Link> does internally
function Link({ to, children, ...props }) {
  function handleClick(event) {
    // Don't intercept modified clicks (open in new tab, etc.)
    if (
      !event.defaultPrevented &&
      event.button === 0 &&       // left click only
      !event.metaKey &&           // not Cmd+Click
      !event.ctrlKey &&           // not Ctrl+Click
      !event.shiftKey &&          // not Shift+Click
      !props.target               // not target="_blank"
    ) {
      event.preventDefault();
      navigate(to);
    }
  }

  return <a href={to} onClick={handleClick} {...props}>{children}</a>;
}

// Portal example — stopPropagation inside a portal still works
// because React's event tree follows the component tree, not the DOM tree.
import { createPortal } from 'react-dom';

function Modal({ onClose, children }) {
  return createPortal(
    <div
      className="modal-backdrop"
      onClick={onClose}  // click backdrop → close
    >
      <div
        className="modal-content"
        onClick={e => e.stopPropagation()}  // click content → DON'T close
      >
        {children}
      </div>
    </div>,
    document.body  // renders outside the React root in the DOM
  );
}
// Despite being in document.body, stopPropagation inside the portal
// prevents the backdrop's onClose from firing — React handles it correctly.

import { useEffect, useRef } from 'react';

function SwipeCarousel({ children }) {
  const ref = useRef(null);

  useEffect(() => {
    const el = ref.current;
    const handleTouchMove = e => {
      // Works because we explicitly set passive: false
      if (isHorizontalSwipe(e)) {
        e.preventDefault();
      }
    };

    el.addEventListener('touchmove', handleTouchMove, { passive: false });
    return () => el.removeEventListener('touchmove', handleTouchMove);
  }, []);

  return <div ref={ref}>{children}</div>;
}

// The React onTouchMove prop cannot call preventDefault (passive by default);
// use a ref + native addEventListener({ passive: false }) when you need it.

function AnalyticsWrapper({ children }) {
  // Fires during capture phase — sees every click before children do
  const handleCapture = e => {
    analytics.track('click', {
      tag: e.target.tagName,
      text: e.target.innerText?.slice(0, 50),
    });
    // Do NOT stopPropagation here — we want children to handle it too
  };

  return <div onClickCapture={handleCapture}>{children}</div>;
}

// Capture + stopPropagation: blocks ALL clicks inside a disabled section
function DisabledOverlay({ disabled, children }) {
  return (
    <div
      onClickCapture={disabled ? e => e.stopPropagation() : undefined}
      style={{ pointerEvents: disabled ? 'none' : 'auto' }}
    >
      {children}
    </div>
  );
}
